#include<bits/stdc++.h>
#include<bits/extc++.h>
using namespace std;
using namespace __gnu_pbds;
long long n,N,ans=INT_MAX,m,a[32],cnt,b[32];
gp_hash_table<long long,long long> mp;
void dfs1(long long x,long long p,long long s)
{
    if(s>m||s+b[x]<m)
    {
        return;
    }
    if(s==m)
    {
        mp[s]=p;
        return;
    }
    if(x==N+1)
    {
        if(mp[s])
        {
            mp[s]=min(mp[s],p+1);
        }
        else
        {
            mp[s]=p+1;
        }
        return;
    }
    dfs1(x+1,p,s+a[x]);
    dfs1(x+1,p+1,s+a[x]/2);
    dfs1(x+1,p,s);
}
void dfs2(long long x,long long p,long long s)
{
    if(s>m||p>ans)
    {
        return;
    }
    if(s==m)
    {
        ans=min(ans,mp[s]+p);
        return;
    }
    if(x==n+1)
    {
        if(mp[m-s])
        {
            ans=min(ans,mp[m-s]+p-1);
        }
        return;
    }
    dfs2(x+1,p,s+a[x]);
    dfs2(x+1,p+1,s+a[x]/2);
    dfs2(x+1,p,s);
}
int main()
{
    scanf("%lld%lld",&n,&m);
    N=min(n/2+1,n-2);
    m*=2;
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        a[i]*=2;
    }
    sort(a+1,a+1+n,greater<long long>());
    for(long long i=n;i>=1;i--)
    {
        b[i]=b[i+1]+a[i];
    }
    dfs1(1,0,0);
    dfs2(N+1,0,0);
    if(ans>1e9)
    {
        printf("-1");
    }
    else
    {
        printf("%lld",ans);
    }
    return 0;
}
